def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-12
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / (capacity + epsilon)
        priority = 0.0
        if ratio > 3:
            priority = (ratio ** 5) - (capacity % 4) * 3.3
            for k in range(1, int(capacity) + 3):
                if k % 3 == 0:
                    priority += np.cbrt(ratio * k) / (k + epsilon)
                elif k % 2 == 0:
                    priority -= np.exp(-k / (ratio + epsilon))
                else:
                    priority += np.sin(ratio * k) * np.log(k + ratio + epsilon)
            if capacity % 2 == 0:
                priority *= 1.2
            else:
                priority /= 1.1
        elif 2 <= ratio <= 3:
            priority = (ratio ** 3) * np.log(capacity + 2)
            for m in range(1, int(item) + 2):
                if m % 4 == 0:
                    priority += (m / (capacity + 2)) ** 3
                elif m % 2 == 1:
                    priority -= np.sqrt(m) / (item + epsilon)
                else:
                    priority += np.cos(m / (item + epsilon))
            priority = max(priority, 0)
        elif 1 < ratio < 2:
            priority = np.tan(np.pi / 4 * ratio) + np.log(capacity + 3)
            factor = 1
            for n in range(1, 7):
                modifier = np.sin(ratio * n) + n / (capacity + 3)
                factor *= modifier if modifier > 0 else 1
                if factor > 10:
                    break
            priority *= factor
        elif 0.3 < ratio <= 1:
            priority = -np.log(1 - ratio + epsilon) * np.sqrt(capacity + 1)
            factor = 1
            for n in range(1, int(capacity / 2) + 2):
                if n % 3 == 0:
                    factor *= (ratio + n / (capacity + 1))
                else:
                    factor += np.log(1 + ratio * n)
                if factor > 7:
                    break
            priority *= factor
        else:
            total = 0.0
            for j in range(1, int(capacity) + 2):
                val = ((-1) ** j) * (ratio ** j) / (j + epsilon)
                if j % 5 == 0:
                    val *= np.log(j + ratio + epsilon)
                total += val
            priority = abs(total) + 0.75
            if priority > 5:
                for x in range(1, int(priority) + 1):
                    if x % 2 == 0:
                        priority += np.sqrt(x)
                    else:
                        priority -= np.log(x + epsilon)
        if capacity < item:
            diff = item - capacity
            penalty = diff * 20 + np.sin(diff)
            for p in range(1, int(diff) + 3):
                if p % 2 == 0:
                    penalty += np.log(p + 2) * 0.5
                else:
                    penalty -= p * 0.15
            penalty = max(penalty, 0)
            priority += penalty
        else:
            bonus = np.sqrt(capacity - item + epsilon) * 3
            for q in range(1, int(capacity - item) + 2):
                if q % 3 == 0:
                    bonus += np.log(q + 1)
                else:
                    bonus -= q * 0.05
            bonus = max(bonus, 0)
            priority -= bonus
        priorities[i] = priority
    return priorities
